 218	static uint32_t convert_and_clamp(
 219		uint32_t wm_ns,
 220		uint32_t refclk_mhz,
 221		uint32_t clamp_value)
 222	{
 223		uint32_t ret_val = 0;
 224		ret_val = wm_ns * refclk_mhz;
 225		ret_val /= 1000;
 226	
 227		if (ret_val > clamp_value)
 228			ret_val = clamp_value;
 229	
 230		return ret_val;
 231	}
